const BATCH = 3;

const enabled = String($env.CONTENT_PAGE_PUBLISH_ENABLED || '').toLowerCase() === 'true';
if (!enabled) {
  return [{
    json: {
      empty: true,
      message: 'CONTENT_PAGE_PUBLISH_ENABLED không bật — set true trên VPS',
    },
  }];
}

const pageId = String($env.META_PAGE_ID || '').trim();
const token = String($env.META_PAGE_ACCESS_TOKEN || '').trim();
if (!pageId || !token) {
  return [{
    json: {
      empty: true,
      message: 'Thiếu META_PAGE_ID hoặc META_PAGE_ACCESS_TOKEN',
    },
  }];
}

const res = $input.first().json || {};
const payload = res.data && typeof res.data === 'object' ? res.data : res;
const items = Array.isArray(payload.items) ? payload.items : [];
const blockers = payload.blockers || null;

if (!items.length) {
  return [{
    json: {
      empty: true,
      message:
        'Không có bài Page due trên Postgres — cần APPROVED + FB_PAGE/meta + scheduled_at<=now (Admin /admin/content-drafts)',
      blockers,
      scanned: payload.scanned ?? 0,
    },
  }];
}

const out = [];
for (const item of items) {
  if (!item?.id) continue;
  out.push({
    json: {
      id: item.id,
      draft_id: item.id,
      normalized_key: item.normalized_key,
      title: item.title,
      hook_line: item.hook_line,
      artifact_markdown: item.artifact_markdown,
      cta_opt_in: item.cta_opt_in,
      disclaimer: item.disclaimer,
      segment: item.segment,
      export_hint: item.export_hint,
      status: item.status,
      publish_channel: item.publish_channel,
      scheduled_at: item.scheduled_at,
      sheet_key: item.sheet_key,
      product_type: item.product_type || 'fb_page_post',
      meta_parsed: item.meta_parsed || {},
      page_id: pageId,
    },
  });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: 'Due list rỗng hoặc thiếu id',
      blockers,
    },
  }];
}

return out;

const data = $getWorkflowStaticData('global');
data.cpp_stats = { publish_ok: 0, publish_fail: 0, l0_fail: 0 };
return $input.all();

const FORBIDDEN = [
  /cam kết.*duyệt/i,
  /lãi suất\s*\d+([.,]\d+)?\s*%/i,
  /đảm bảo.*(vay|duyệt)/i,
  /100%\s*(thành công|duyệt)/i,
];

function stripMarkdownHeavy(md) {
  return String(md || '')
    .replace(/```[\s\S]*?```/g, '')
    .replace(/\|[-:\s|]+\|/g, '')
    .replace(/\|/g, ' ')
    .replace(/#{1,6}\s/g, '')
    .replace(/\*\*/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function excerpt(text, max = 6000) {
  const t = String(text || '').trim();
  if (t.length <= max) return t;
  return `${t.slice(0, max - 1)}…`;
}

const row = $('Loop Page Publish').item?.json || $input.first().json;
const meta = row.meta_parsed || {};

const hook = String(row.hook_line || meta.hook || '').trim();
const bodyRaw = String(meta.publish_body || row.artifact_markdown || '').trim();
const body = excerpt(stripMarkdownHeavy(bodyRaw), 5500);
const cta = String(row.cta_opt_in || meta.cta || '').trim();
const disclaimer = String(row.disclaimer || meta.disclaimer || '').trim();
const hashtags = Array.isArray(meta.hashtags)
  ? meta.hashtags.map(String).join(' ')
  : String(meta.hashtags || '#NOXH #nhàởxãhội').trim();

const parts = [];
if (hook) parts.push(hook);
if (body) parts.push(body);
if (cta) parts.push(cta);
if (disclaimer) parts.push(disclaimer);
if (hashtags) parts.push(hashtags);

const message = parts.join('\n\n').trim().slice(0, 63000);

const hits = FORBIDDEN.filter((re) => re.test(message)).map((re) => re.source);
const draftId = row.id || row.draft_id || null;

if (hits.length) {
  return [{
    json: {
      ok: false,
      error: 'L0_FORBIDDEN',
      l0_hits: hits,
      id: draftId,
      draft_id: draftId,
      normalized_key: row.normalized_key,
    },
  }];
}

const link = String(meta.publish_link || meta.link || meta.drive_pack_url || '').trim();
const imageUrl = String(meta.publish_image_url || meta.cover_image_url || '').trim();
const pinAfter = meta.pin_after_publish === true;

return [{
  json: {
    ok: true,
    id: draftId,
    draft_id: draftId,
    normalized_key: row.normalized_key,
    segment: row.segment,
    title: String(row.title || '').slice(0, 200),
    message,
    link: link || null,
    publish_image_url: imageUrl || null,
    pin_after_publish: pinAfter,
    page_id: row.page_id || $env.META_PAGE_ID,
    product_type: row.product_type || meta.product_type || 'fb_page_post',
  },
}];

const item = $input.first().json;
if (!item.ok || !item.message) {
  return [{ json: { ...item, publish_ok: false } }];
}

const version = String($env.META_GRAPH_API_VERSION || 'v21.0').trim();
const pageId = String(item.page_id || $env.META_PAGE_ID || '').trim();
const token = String($env.META_PAGE_ACCESS_TOKEN || '').trim();

if (!pageId || !token) {
  return [{
    json: {
      ...item,
      publish_ok: false,
      publish_error: 'MISSING_META_CREDENTIALS',
    },
  }];
}

const imageUrl = String(item.publish_image_url || '').trim();
const link = String(item.link || '').trim();

const body = {
  message: item.message,
  access_token: token,
};

let endpoint = `/${pageId}/feed`;
if (imageUrl) {
  body.url = imageUrl;
  endpoint = `/${pageId}/photos`;
} else if (link) {
  body.link = link;
}

function toFormUrlEncoded(data) {
  return Object.entries(data)
    .filter(([, v]) => v !== undefined && v !== null && v !== '')
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

try {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/${version}${endpoint}`,
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: toFormUrlEncoded(body),
    json: true,
    timeout: 30000,
  });

  const postId = res.id || res.post_id || null;
  if (!postId) {
    return [{
      json: {
        ...item,
        publish_ok: false,
        publish_error: 'NO_POST_ID_IN_RESPONSE',
        graph_response: res,
        publish_mode: imageUrl ? 'photo' : link ? 'link' : 'text',
      },
    }];
  }

  return [{
    json: {
      ...item,
      publish_ok: true,
      fb_post_id: postId,
      fb_permalink: `https://www.facebook.com/${postId}`,
      published_at: new Date().toISOString(),
      graph_response: { id: postId },
      publish_mode: imageUrl ? 'photo' : link ? 'link' : 'text',
    },
  }];
} catch (e) {
  const graph = e.response?.data || e.cause?.response?.data || e.description || e.message;
  const fbMsg = graph?.error?.message || (typeof graph === 'string' ? graph : null);
  return [{
    json: {
      ...item,
      publish_ok: false,
      publish_error: fbMsg || JSON.stringify(graph).slice(0, 500),
      publish_error_code: graph?.error?.code || null,
      publish_mode: imageUrl ? 'photo' : link ? 'link' : 'text',
    },
  }];
}

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const METRICS_TAB = 'content_metrics';

const item = $input.first().json;
const loopRow = $('Loop Page Publish').item?.json || {};
const draftId = item.id || item.draft_id || loopRow.id || loopRow.draft_id;

if (!draftId) {
  return [{ json: { ok: false, skip: true, reason: 'NO_DRAFT_ID' } }];
}

const base = String(
  $env.HOUSEX_PUBLIC_URL || $env.NEXT_PUBLIC_SITE_URL || 'https://timnhaxahoi.com',
).replace(/\/$/, '');

const out = {
  ...item,
  id: draftId,
  draft_id: draftId,
  normalized_key: item.normalized_key || loopRow.normalized_key || null,
  segment: item.segment || loopRow.segment || null,
  title: item.title || loopRow.title || null,
  housex_mark_url: `${base}/api/cron/content-page-publish-due`,
  housex_mark_body: {
    id: draftId,
    publish_ok: item.publish_ok === true,
    fb_post_id: item.fb_post_id || null,
    fb_permalink: item.fb_permalink || null,
    publish_error: item.publish_error || null,
    publish_mode: item.publish_mode || null,
    pin_after_publish: item.pin_after_publish === true,
  },
  housex_mark_headers: {
    Authorization: `Bearer ${String($env.CRON_SECRET || '').trim()}`,
    'Content-Type': 'application/json',
  },
  need_metrics_append: item.publish_ok === true && Boolean(item.fb_post_id),
};

if (out.need_metrics_append) {
  out.metrics_append_url = `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${METRICS_TAB}!A:F`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`;
  out.metrics_append_body = {
    values: [[
      String(item.fb_post_id),
      'fb_page',
      String(out.segment || ''),
      String(out.title || '').slice(0, 200),
      new Date().toISOString(),
      'pending',
    ]],
  };
}

return [{ json: out }];

const prep = $('Prepare Postgres Mark').item.json;

const data = $getWorkflowStaticData('global');
if (!data.cpp_stats) data.cpp_stats = { publish_ok: 0, publish_fail: 0, l0_fail: 0 };

if (prep.publish_ok) data.cpp_stats.publish_ok += 1;
else data.cpp_stats.publish_fail += 1;

let metricsAppended = false;
if (prep.need_metrics_append === true) {
  const m = $input.first().json || {};
  metricsAppended = Boolean(m.updates || m.spreadsheetId || m.updatedRange);
}

return [{
  json: {
    ok: prep.publish_ok === true,
    id: prep.id || prep.draft_id,
    normalized_key: prep.normalized_key,
    fb_post_id: prep.fb_post_id || null,
    fb_permalink: prep.fb_permalink || null,
    metrics_appended: metricsAppended,
    publish_error: prep.publish_error || null,
  },
}];

const prep = $('Prepare Postgres Mark').item?.json || $('POST Facebook Page Feed').item?.json || {};

if (!prep.publish_ok || !prep.pin_after_publish || !prep.fb_post_id) {
  return [{ json: { pin_notify_skipped: true, reason: 'NO_PIN_REQUEST' } }];
}

const enabled = String($env.TELEGRAM_APPROVAL_ENABLED || '').toLowerCase() === 'true';
if (!enabled) {
  return [{
    json: {
      pin_notify_skipped: true,
      reason: 'TELEGRAM_APPROVAL_ENABLED',
      fb_post_id: prep.fb_post_id,
      fb_permalink: prep.fb_permalink,
    },
  }];
}

const token = $env.MAGNIX_WEBHOOK_TOKEN || '';
const base = String($env.N8N_PUBLIC_URL || 'https://n8n.vmd.asia').replace(/\/$/, '');
const eventId = `pin:${prep.fb_post_id}:${Date.now()}`;

const body = {
  event_id: eventId,
  event_type: 'pin_page_post_requested',
  title: prep.title || 'Facebook Page post',
  message: [
    '📌 **Ghim bài trên Page** (Meta API không hỗ trợ ghim đầy đủ — thao tác tay)',
    '',
    `Post: ${prep.fb_permalink || prep.fb_post_id}`,
    `Draft: ${prep.id || prep.draft_id || prep.normalized_key || '—'}`,
    '',
    'Meta Business Suite → Page → Posts → Ghim',
  ].join('\n'),
  draft_id: prep.id || prep.draft_id || null,
  meta: {
    fb_post_id: prep.fb_post_id,
    fb_permalink: prep.fb_permalink,
    pin_after_publish: true,
  },
};

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${base}/webhook/magnix/telegram-notify`,
    headers: {
      Authorization: token ? `Bearer ${token}` : '',
      'Content-Type': 'application/json',
    },
    body,
    json: true,
    timeout: 15000,
  });
  return [{ json: { pin_notify_fired: true, event_id: eventId, fb_post_id: prep.fb_post_id } }];
} catch (e) {
  return [{ json: { pin_notify_fired: false, pin_notify_error: e.message || 'NOTIFY_FAIL', fb_post_id: prep.fb_post_id } }];
}

const data = $getWorkflowStaticData('global');
if (!data.cpp_stats) data.cpp_stats = {};
data.cpp_stats.l0_fail = (data.cpp_stats.l0_fail || 0) + 1;
data.cpp_stats.publish_fail = (data.cpp_stats.publish_fail || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
const stats = data.cpp_stats || {};
let hint = null;
if ((stats.publish_ok || 0) === 0) {
  if (stats.no_candidates) hint = 'Không candidate — sync Sheet→Admin, APPROVED + kênh FB_PAGE + lịch <= now';
  else if ((stats.l0_fail || 0) > 0) hint = 'L0 forbidden — sửa nội dung trên /admin/content-drafts';
  else if ((stats.publish_fail || 0) > 0) hint = 'Graph API fail — kiểm tra META_PAGE_ACCESS_TOKEN + quyền pages_manage_posts';
  else hint = 'Bật CONTENT_PAGE_PUBLISH_ENABLED=true và điền META_PAGE_ID + CRON_SECRET + HOUSEX_PUBLIC_URL';
}
return [{ json: {
  ok: true,
  workflow: 'content-page-publish',
  source: 'postgres',
  stats,
  batch_size: 3,
  hint,
  finished_at: new Date().toISOString(),
}}];

const data = $getWorkflowStaticData('global');
if (!data.cpp_stats) data.cpp_stats = {};
data.cpp_stats.no_candidates = true;
const msg = $input.first()?.json?.message || 'No page publish candidates';
return [{ json: { ok: true, empty: true, message: msg, blockers: $input.first()?.json?.blockers } }];
